  1	import * as React from 'react';
  2	import {
  3	  getBadge,
  4	  getLink,
  5	  renderBadgedHost,
  6	  renderBadgedLink,
  7	  renderDestServicesLinks,
  8	  renderHealth
  9	} from './SummaryLink';
 10	import { DecoratedGraphNodeData, DestService, NodeType, RankResult, SummaryPanelPropType } from '../../types/Graph';
 11	import { getTitle, summaryBodyTabs, summaryFont, summaryPanel } from './SummaryPanelCommon';
 12	import { KialiIcon } from 'config/KialiIcon';
 13	import { clickHandler, getOptions } from 'pages/Graph/ContextMenu/NodeContextMenu';
 14	import {
 15	  Dropdown,
 16	  DropdownGroup,
 17	  DropdownItem,
 18	  DropdownList,
 19	  ExpandableSection,
 20	  MenuToggle,
 21	  MenuToggleElement,
 22	  Tab
 23	} from '@patternfly/react-core';
 24	import { SummaryPanelNodeTraffic } from './SummaryPanelNodeTraffic';
 25	import { SummaryPanelNodeTraces } from './SummaryPanelNodeTraces';
 26	import { SimpleTabs } from 'components/Tab/SimpleTabs';
 27	import { TracingState } from 'reducers/TracingState';
 28	import { classes } from 'typestyle';
 29	import { kialiStyle } from 'styles/StyleUtils';
 30	import { PFBadge, PFBadges } from 'components/Pf/PfBadges';
 31	import { ServiceDetailsInfo } from 'types/ServiceInfo';
 32	import { LoadingWizardActionsDropdownGroup } from 'components/IstioWizards/LoadingWizardActionsDropdownGroup';
 33	import { WizardAction, WizardMode } from 'components/IstioWizards/WizardActions';
 34	import { ServiceWizardActionsDropdownGroup } from 'components/IstioWizards/ServiceWizardActionsDropdownGroup';
 35	import { PeerAuthentication } from '../../types/IstioObjects';
 36	import { useServiceDetailForGraphNode } from '../../hooks/services';
 37	import { useKialiSelector } from '../../hooks/redux';
 38	import { groupMenuStyle, kebabToggleStyle } from 'styles/DropdownStyles';
 39	import { isMultiCluster, serverConfig } from '../../config';
 40	import { panelBodyStyle, panelHeadingStyle, panelStyle } from './SummaryPanelStyle';
 41	import { dicTypeToGVK, gvkType } from '../../types/IstioConfigList';
 42	import { renderWaypointLabel } from '../../components/Ambient/WaypointLabel';
 43	import { Node } from '@patternfly/react-topology';
 44	import { KialiPageLink } from 'components/Link/KialiPageLink';
 45	import { KioskData, KioskMode } from 'types/Common';
 46	
 47	type SummaryPanelNodeState = {
 48	  isActionOpen: boolean;
 49	};
 50	
 51	const defaultState: SummaryPanelNodeState = {
 52	  isActionOpen: false
 53	};
 54	
 55	type ReduxProps = {
 56	  kiosk: KioskMode;
 57	  kioskData?: KioskData;
 58	  rankResult: RankResult;
 59	  showRank: boolean;
 60	  tracingState: TracingState;
 61	};
 62	
 63	export type SummaryPanelNodeProps = Omit<SummaryPanelPropType, 'kiosk'> & {
 64	  onDeleteTrafficRouting?: (key: string, serviceDetails: ServiceDetailsInfo) => void;
 65	  onLaunchWizard?: (
 66	    key: WizardAction,
 67	    mode: WizardMode,
 68	    namespace: string,
 69	    serviceDetails: ServiceDetailsInfo,
 70	    gateways: string[],
 71	    peerAuths: PeerAuthentication[]
 72	  ) => void;
 73	};
 74	
 75	export type SummaryPanelNodeComponentProps = ReduxProps &
 76	  SummaryPanelNodeProps & {
 77	    gateways: string[] | null;
 78	    onKebabToggled?: (isOpen: boolean) => void;
 79	    peerAuthentications: PeerAuthentication[] | null;
 80	    serviceDetails: ServiceDetailsInfo | null | undefined;
 81	  };
 82	
 83	const expandableSectionStyle = kialiStyle({
 84	  fontSize: 'var(--graph-side-panel--font-size)',
 85	  paddingLeft: '1rem',
 86	  $nest: {
 87	    '& > div': {
 88	      marginLeft: '2rem',
 89	      marginTop: '0 !important',
 90	      $nest: {
 91	        '& div': {
 92	          overflow: 'hidden',
 93	          textOverflow: 'ellipsis',
 94	          whiteSpace: 'nowrap'
 95	        }
 96	      }
 97	    }
 98	  }
 99	});
100	
101	const nodeInfoStyle = kialiStyle({
102	  display: 'flex',
103	  alignItems: 'center',
104	  marginTop: '0.25rem'
105	});
106	
107	const workloadExpandableSectionStyle = classes(expandableSectionStyle, kialiStyle({ display: 'inline' }));
108	
109	export class SummaryPanelNodeComponent extends React.Component<SummaryPanelNodeComponentProps, SummaryPanelNodeState> {
110	  private readonly mainDivRef: React.RefObject<HTMLDivElement>;
111	
112	  constructor(props: SummaryPanelNodeComponentProps) {
113	    super(props);
114	
115	    this.state = { ...defaultState };
116	    this.mainDivRef = React.createRef<HTMLDivElement>();
117	  }
118	
119	  componentDidUpdate(prevProps: SummaryPanelNodeComponentProps): void {
120	    if (prevProps.data.summaryTarget !== this.props.data.summaryTarget) {
121	      if (this.mainDivRef.current) {
122	        this.mainDivRef.current.scrollTop = 0;
123	      }
124	    }
125	  }
126	
127	  render(): React.ReactNode {
128	    const node = this.props.data.summaryTarget as Node;
129	    const nodeData = node.getData();
130	    const { nodeType, app, service, workload, isServiceEntry } = nodeData;
131	    const servicesList = nodeType !== NodeType.SERVICE && renderDestServicesLinks(nodeData);
132	    const destsList = nodeType === NodeType.SERVICE && isServiceEntry && this.renderDestServices(nodeData);
133	
134	    const hasNetobserv = this.props.kioskData?.hasNetobserv;
135	    const shouldRenderDestsList = destsList && destsList.length > 0;
136	    const shouldRenderSvcList = servicesList && servicesList.length > 0;
137	    const shouldRenderService = service && ![NodeType.SERVICE, NodeType.UNKNOWN].includes(nodeType);
138	    const shouldRenderApp = app && ![NodeType.APP, NodeType.UNKNOWN].includes(nodeType) && !nodeData.isWaypoint;
139	    const shouldRenderWorkload = workload && ![NodeType.WORKLOAD, NodeType.UNKNOWN].includes(nodeType);
140	    const shouldRenderNetobservWorkload = hasNetobserv && (nodeType === NodeType.WORKLOAD || shouldRenderWorkload);
141	    const shouldRenderTraces =
142	      !isServiceEntry &&
143	      !nodeData.isInaccessible &&
144	      this.props.tracingState.info &&
145	      this.props.tracingState.info.enabled &&
146	      this.props.tracingState.info.integration;
147	
148	    const options = getOptions(nodeData);
149	    const items = [
150	      <DropdownGroup key="show" label="Show" className={groupMenuStyle}>
151	        {options.map((o, i) => {
152	          return (
153	            <DropdownItem key={`option-${i}`} onClick={() => clickHandler(o, this.props.kiosk)}>
154	              {o.text} {o.target === '_blank' && <KialiIcon.ExternalLink />}
155	            </DropdownItem>
156	          );
157	        })}
158	      </DropdownGroup>
159	    ];
160	
161	    if (nodeType === NodeType.SERVICE) {
162	      if (this.props.serviceDetails === undefined) {
163	        items.push(<LoadingWizardActionsDropdownGroup />);
164	      } else if (this.props.serviceDetails !== null) {
165	        items.push(
166	          <ServiceWizardActionsDropdownGroup
167	            virtualServices={this.props.serviceDetails.virtualServices ?? []}
168	            destinationRules={this.props.serviceDetails.destinationRules ?? []}
169	            k8sHTTPRoutes={this.props.serviceDetails.k8sHTTPRoutes ?? []}
170	            k8sGRPCRoutes={this.props.serviceDetails.k8sGRPCRoutes ?? []}
171	            istioPermissions={this.props.serviceDetails.istioPermissions}
172	            onAction={this.handleLaunchWizard}
173	            onDelete={this.handleDeleteTrafficRouting}
174	          />
175	        );
176	      }
177	    }
178	
179	    const firstBadge = isMultiCluster ? (
180	      <>
181	        <PFBadge badge={PFBadges.Cluster} size="sm" />
182	        {nodeData.cluster}
183	      </>
184	    ) : (
185	      <>
186	        <PFBadge badge={PFBadges.Namespace} size="sm" />
187	        {nodeData.namespace}
188	      </>
189	    );
190	
191	    const secondBadge = isMultiCluster ? (
192	      <div>
193	        <PFBadge badge={PFBadges.Namespace} size="sm" />
194	        {nodeData.namespace}
195	      </div>
196	    ) : (
197	      <></>
198	    );
199	
200	    // Note: NetObserv link removed per current requirements
201	
202	    return (
203	      <div ref={this.mainDivRef} className={classes(panelStyle, summaryPanel)}>
204	        <div className={panelHeadingStyle}>
205	          {getTitle(nodeType)}
206	
207	          <div>
208	            <span>
209	              {firstBadge}
210	
211	              {options.length > 0 && (
212	                <Dropdown
213	                  id="summary-node-actions"
214	                  toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
215	                    <MenuToggle
216	                      ref={toggleRef}
217	                      id="summary-node-kebab"
218	                      className={kebabToggleStyle}
219	                      aria-label="Actions"
220	                      variant="plain"
221	                      onClick={() => this.onToggleActions(!this.state.isActionOpen)}
222	                      isExpanded={this.state.isActionOpen}
223	                      style={{ float: 'right' }}
224	                    >
225	                      <KialiIcon.KebabToggle />
226	                    </MenuToggle>
227	                  )}
228	                  isOpen={this.state.isActionOpen}
229	                  onOpenChange={(isOpen: boolean) => this.onToggleActions(isOpen)}
230	                  popperProps={{ position: 'right', enableFlip: true }}
231	                >
232	                  <DropdownList>{items}</DropdownList>
233	                </Dropdown>
234	              )}
235	
236	              {secondBadge}
237	              {!nodeData.isWaypoint && (
238	                <div className={nodeInfoStyle}>
239	                  {renderBadgedLink(nodeData)}
240	                  {renderHealth(nodeData.health)}
241	                </div>
242	              )}
243	            </span>
244	          </div>
245	
246	          <div>
247	            {this.renderBadgeSummary(nodeData)}
248	            {nodeData.isWaypoint && renderWaypointLabel('sm')}
249	            {shouldRenderDestsList && <div>{destsList}</div>}
250	            {shouldRenderSvcList && <div key={Date.now()}>{servicesList}</div>}
251	            {shouldRenderService && <div>{renderBadgedLink(nodeData, NodeType.SERVICE)}</div>}
252	            {shouldRenderApp && <div>{renderBadgedLink(nodeData, NodeType.APP)}</div>}
253	            {shouldRenderWorkload && this.renderWorkloadSection(nodeData)}
254	            {shouldRenderNetobservWorkload && this.renderNetobservLink(nodeData, NodeType.WORKLOAD)}
255	          </div>
256	        </div>
257	
258	        {shouldRenderTraces ? this.renderWithTabs(nodeData) : this.renderTrafficOnly()}
259	      </div>
260	    );
261	  }
262	
263	  // this is relevant only to linking to a netobserv tab in OSSMC
264	  private renderNetobservLink = (nodeData: DecoratedGraphNodeData, nodeType: NodeType): React.ReactNode => {
265	    // prefix the workload or service link with '/netobserv' to indicate that we want to link
266	    // to the netobserv 'Network Traffic' tab for the entity, not the 'Service Mesh' tab. The link will be intercepted
267	    // by KialiIntegration in OSSM, and redirected as needed.
268	    const link = `/netobserv${getLink(nodeData, nodeType).link}`;
269	    return (
270	      <div className={nodeInfoStyle}>
271	        <PFBadge badge={PFBadges.NetworkTraffic} size="sm" />
272	        <KialiPageLink href={link} cluster={nodeData.cluster}>
273	          network traffic
274	        </KialiPageLink>
275	      </div>
276	    );
277	  };
278	
279	  private renderWorkloadSection = (nodeData: DecoratedGraphNodeData): React.ReactNode => {
280	    if (!nodeData.hasWorkloadEntry) {
281	      return <div>{renderBadgedLink(nodeData, NodeType.WORKLOAD)}</div>;
282	    }
283	    const weGVK = dicTypeToGVK[gvkType.WorkloadEntry];
284	
285	    const workloadEntryLinks = nodeData.hasWorkloadEntry.map(we => (
286	      <div>
287	        {
288	          getLink(nodeData, NodeType.WORKLOAD, () => ({
289	            link: `/namespaces/${encodeURIComponent(nodeData.namespace)}/istio/${weGVK.Group}/${weGVK.Version}/${
290	              weGVK.Kind
291	            }/${encodeURIComponent(we.name)}`,
292	            displayName: we.name,
293	            key: `${nodeData.namespace}.wle.${we.name}`
294	          })).elem
295	        }
296	      </div>
297	    ));
298	
299	    return (
300	      <>
301	        {getBadge(nodeData, NodeType.WORKLOAD)}
302	
303	        <ExpandableSection
304	          toggleText={
305	            nodeData.hasWorkloadEntry.length === 1
306	              ? '1 workload entry'
307	              : `${nodeData.hasWorkloadEntry.length} workload entries`
308	          }
309	          className={workloadExpandableSectionStyle}
310	        >
311	          <div style={{ marginLeft: '3.5em' }}>{workloadEntryLinks}</div>
312	        </ExpandableSection>
313	      </>
314	    );
315	  };
316	
317	  private renderGatewayHostnames = (nodeData: DecoratedGraphNodeData): React.ReactNode => {
318	    if (nodeData.isGateway?.ingressInfo?.hostnames && nodeData.isGateway?.ingressInfo?.hostnames.length > 0) {
319	      return this.renderHostnamesSection(nodeData.isGateway?.ingressInfo?.hostnames);
320	    }
321	
322	    if (nodeData.isGateway?.egressInfo?.hostnames && nodeData.isGateway?.egressInfo?.hostnames.length > 0) {
323	      return this.renderHostnamesSection(nodeData.isGateway?.egressInfo?.hostnames);
324	    }
325	
326	    if (nodeData.isGateway?.gatewayAPIInfo?.hostnames && nodeData.isGateway?.gatewayAPIInfo?.hostnames.length > 0) {
327	      return this.renderHostnamesSection(nodeData.isGateway?.gatewayAPIInfo?.hostnames);
328	    }
329	
330	    return null;
331	  };
332	
333	  private renderVsHostnames = (nodeData: DecoratedGraphNodeData): React.ReactNode => {
334	    return this.renderHostnamesSection(nodeData.hasVS?.hostnames!);
335	  };
336	
337	  private renderHostnamesSection = (hostnames: string[]): React.ReactNode => {
338	    const numberOfHostnames = hostnames.length;
339	    let toggleText = `${numberOfHostnames} hosts`;
340	
341	    if (numberOfHostnames === 1) {
342	      toggleText = '1 host';
343	    }
344	
345	    return (
346	      <ExpandableSection toggleText={toggleText} className={expandableSectionStyle}>
347	        {hostnames.map(hostname => (
348	          <div key={hostname} title={hostname}>
349	            {hostname === '*' ? '* (all hosts)' : hostname}
350	          </div>
351	        ))}
352	      </ExpandableSection>
353	    );
354	  };
355	
356	  private renderTrafficOnly(): React.ReactNode {
357	    return (
358	      <div className={panelBodyStyle}>
359	        <SummaryPanelNodeTraffic {...this.props} />
360	      </div>
361	    );
362	  }
363	
364	  private renderWithTabs(nodeData: DecoratedGraphNodeData): React.ReactNode {
365	    return (
366	      <div className={summaryBodyTabs}>
367	        <SimpleTabs id="graph_summary_tabs" defaultTab={0} style={{ paddingBottom: '0.5rem' }}>
368	          <Tab style={summaryFont} title="Traffic" eventKey={0}>
369	            <div style={summaryFont}>
370	              <SummaryPanelNodeTraffic {...this.props} />
371	            </div>
372	          </Tab>
373	
374	          <Tab style={summaryFont} title="Traces" eventKey={1}>
375	            <SummaryPanelNodeTraces
376	              kiosk={this.props.kiosk}
377	              nodeData={nodeData}
378	              queryTime={this.props.queryTime - this.props.duration}
379	            />
380	          </Tab>
381	        </SimpleTabs>
382	      </div>
383	    );
384	  }
385	
386	  private onToggleActions = (isOpen: boolean): void => {
387	    this.setState({ isActionOpen: isOpen });
388	
389	    if (this.props.onKebabToggled) {
390	      this.props.onKebabToggled(isOpen);
391	    }
392	  };
393	
394	  private renderK8sGatewayAPI(isK8sGatewayAPI?: boolean): React.ReactNode {
395	    return isK8sGatewayAPI ? ' (K8s GW API)' : '';
396	  }
397	
398	  // TODO:(see https://github.com/kiali/kiali-design/issues/63) If we want to show an icon for SE uncomment below
399	  private renderBadgeSummary = (nodeData: DecoratedGraphNodeData): React.ReactNode => {
400	    const {
401	      hasCB,
402	      hasFaultInjection,
403	      hasMirroring,
404	      hasRequestRouting,
405	      hasRequestTimeout,
406	      hasTCPTrafficShifting,
407	      hasTrafficShifting,
408	      hasVS,
409	      isDead,
410	      isGateway,
411	      isK8sGatewayAPI,
412	      isOutOfMesh
413	    } = nodeData;
414	
415	    const hasTrafficScenario =
416	      hasRequestRouting ||
417	      hasFaultInjection ||
418	      hasMirroring ||
419	      hasTrafficShifting ||
420	      hasTCPTrafficShifting ||
421	      hasRequestTimeout;
422	
423	    const shouldRenderGatewayHostnames =
424	      (nodeData.isGateway?.ingressInfo?.hostnames !== undefined &&
425	        nodeData.isGateway.ingressInfo.hostnames.length !== 0) ||
426	      (nodeData.isGateway?.egressInfo?.hostnames !== undefined &&
427	        nodeData.isGateway.egressInfo.hostnames.length !== 0) ||
428	      (nodeData.isGateway?.gatewayAPIInfo?.hostnames !== undefined &&
429	        nodeData.isGateway.gatewayAPIInfo.hostnames.length !== 0);
430	
431	    const shouldRenderVsHostnames = nodeData.hasVS?.hostnames !== undefined && nodeData.hasVS?.hostnames.length !== 0;
432	
433	    const shouldRenderRank = this.props.showRank;
434	
435	    return (
436	      <div style={{ marginTop: '0.5rem', marginBottom: '0.5rem' }}>
437	        {hasCB && (
438	          <div>
439	            <KialiIcon.CircuitBreaker />
440	            <span style={{ paddingLeft: '0.25rem' }}>
441	              Has Circuit Breaker{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
442	            </span>
443	          </div>
444	        )}
445	
446	        {hasVS && !hasTrafficScenario && (
447	          <>
448	            <div>
449	              <KialiIcon.VirtualService />
450	              <span style={{ paddingLeft: '0.25rem' }}>
451	                Has Virtual Service{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
452	              </span>
453	            </div>
454	            {shouldRenderVsHostnames && this.renderVsHostnames(nodeData)}
455	          </>
456	        )}
457	
458	        {hasMirroring && (
459	          <div>
460	            <KialiIcon.Mirroring />
461	            <span style={{ paddingLeft: '0.25rem' }}>Has Mirroring{this.renderK8sGatewayAPI(isK8sGatewayAPI)}</span>
462	          </div>
463	        )}
464	
465	        {isOutOfMesh && !serverConfig.ambientEnabled && (
466	          <div>
467	            <KialiIcon.OutOfMesh />
468	            <span style={{ paddingLeft: '0.25rem' }}>Has Missing Sidecar</span>
469	          </div>
470	        )}
471	
472	        {isOutOfMesh && serverConfig.ambientEnabled && (
473	          <div>
474	            <KialiIcon.OutOfMesh />
475	            <span style={{ paddingLeft: '0.25rem' }}>Out of Mesh</span>
476	          </div>
477	        )}
478	
479	        {isDead && (
480	          <div>
481	            <span style={{ marginRight: '0.25rem' }}>
482	              <KialiIcon.Info />
483	            </span>
484	            <span style={{ paddingLeft: '0.25rem' }}>Has No Running Pods</span>
485	          </div>
486	        )}
487	
488	        {hasRequestRouting && (
489	          <>
490	            <div>
491	              <KialiIcon.RequestRouting />
492	              <span style={{ paddingLeft: '0.25rem' }}>
493	                Has Request Routing{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
494	              </span>
495	            </div>
496	            {shouldRenderVsHostnames && this.renderVsHostnames(nodeData)}
497	          </>
498	        )}
499	
500	        {hasFaultInjection && (
501	          <div>
502	            <KialiIcon.FaultInjection />
503	            <span style={{ paddingLeft: '0.25rem' }}>
504	              Has Fault Injection{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
505	            </span>
506	          </div>
507	        )}
508	
509	        {hasTrafficShifting && (
510	          <div>
511	            <KialiIcon.TrafficShifting />
512	            <span style={{ paddingLeft: '0.25rem' }}>
513	              Has Traffic Shifting{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
514	            </span>
515	          </div>
516	        )}
517	
518	        {hasTCPTrafficShifting && (
519	          <div>
520	            <KialiIcon.TrafficShifting />
521	            <span style={{ paddingLeft: '0.25rem' }}>
522	              Has TCP Traffic Shifting{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
523	            </span>
524	          </div>
525	        )}
526	
527	        {hasRequestTimeout && (
528	          <div>
529	            <KialiIcon.RequestTimeout />
530	            <span style={{ paddingLeft: '0.25rem' }}>
531	              Has Request Timeout{this.renderK8sGatewayAPI(isK8sGatewayAPI)}
532	            </span>
533	          </div>
534	        )}
535	
536	        {isGateway && (
537	          <>
538	            <div>
539	              <KialiIcon.Gateway />
540	              <span style={{ paddingLeft: '0.25rem' }}>Is Gateway{this.renderK8sGatewayAPI(isK8sGatewayAPI)}</span>
541	            </div>
542	            {shouldRenderGatewayHostnames && this.renderGatewayHostnames(nodeData)}
543	          </>
544	        )}
545	
546	        {shouldRenderRank && (
547	          <div>
548	            <KialiIcon.Rank />
549	            <span style={{ paddingLeft: '0.25rem' }}>
550	              Rank: {nodeData.rank !== undefined ? `${nodeData.rank} / ${this.props.rankResult.upperBound}` : 'N/A'}
551	            </span>
552	          </div>
553	        )}
554	      </div>
555	    );
556	  };
557	
558	  private renderDestServices = (data: DecoratedGraphNodeData): React.ReactNode => {
559	    const destServices: DestService[] | undefined = data.destServices;
560	
561	    const entries: React.ReactNode[] = [];
562	
563	    if (!destServices) {
564	      return entries;
565	    }
566	
567	    destServices.forEach(ds => {
568	      entries.push(renderBadgedHost(ds.name));
569	    });
570	
571	    return entries;
572	  };
573	
574	  private handleLaunchWizard = (key: WizardAction, mode: WizardMode): void => {
575	    this.onToggleActions(false);
576	
577	    if (this.props.onLaunchWizard) {
578	      const node = this.props.data.summaryTarget as Node;
579	      const nodeData = node.getData();
580	
581	      this.props.onLaunchWizard(
582	        key,
583	        mode,
584	        nodeData.namespace,
585	        this.props.serviceDetails!,
586	        this.props.gateways!,
587	        this.props.peerAuthentications!
588	      );
589	    }
590	  };
591	
592	  private handleDeleteTrafficRouting = (key: string): void => {
593	    this.onToggleActions(false);
594	
595	    if (this.props.onDeleteTrafficRouting) {
596	      this.props.onDeleteTrafficRouting(key, this.props.serviceDetails!);
597	    }
598	  };
599	}
600	
601	export const SummaryPanelNode: React.FC<SummaryPanelNodeProps> = (props: SummaryPanelNodeProps) => {
602	  const tracingState = useKialiSelector(state => state.tracingState);
603	  const kiosk = useKialiSelector(state => state.globalState.kiosk);
604	  const kioskData = useKialiSelector(state => state.globalState.kioskData);
605	  const rankResult = useKialiSelector(state => state.graph.rankResult);
606	  const showRank = useKialiSelector(state => state.graph.toolbarState.showRank);
607	  const updateTime = useKialiSelector(state => state.graph.updateTime);
608	
609	  const [isKebabOpen, setIsKebabOpen] = React.useState<boolean>(false);
610	
611	  const node = props.data.summaryTarget as Node;
612	  const nodeData = node.getData();
613	
