618	    updateTime
619	  );
620	
621	  const handleKebabToggled = (isOpen: boolean): void => {
622	    setIsKebabOpen(isOpen);
623	  };
624	
625	  return (
626	    <SummaryPanelNodeComponent
627	      tracingState={tracingState}
628	      kiosk={kiosk}
629	      kioskData={kioskData}
630	      rankResult={rankResult}
631	      showRank={showRank}
632	      serviceDetails={isServiceDetailsLoading ? undefined : serviceDetails}
633	      gateways={gateways}
634	      peerAuthentications={peerAuthentications}
635	      onKebabToggled={handleKebabToggled}
636	      {...props}
637	    />
638	  );
639	};

