  7	import { store } from '../../../store/ConfigStore';
  8	import { Provider } from 'react-redux';
  9	import { serverConfig, setServerConfig } from '../../../config/ServerConfig';
 10	
 11	let defaultProps: SummaryPanelNodeComponentProps;
