 17	      id: '1234',
 18	      app: 'ratings',
 19	      cluster: 'Kubernetes',
 20	      nodeType: NodeType.APP,
 21	      namespace: 'bookinfo',
 22	      destServices: []
 23	    };
 24	    const target = {
 25	      data: (destServices?) => (destServices ? [] : nodeData),
 26	      getData: () => {
 27	        return nodeData;
 28	      }
