 34	        summaryTarget: target
 35	      },
 36	      duration: 15,
 37	      graphType: GraphType.VERSIONED_APP,
 38	      injectServiceNodes: false,
 39	      kiosk: '',
 40	      kioskData: undefined,
 41	      namespaces: [],
 42	      queryTime: 20,
 43	      rankResult: { upperBound: 0 },
 44	      showRank: false,
 45	      rateInterval: '30s',
 46	      step: 15,
 47	      trafficRates: [],
 48	      gateways: null,
 49	      peerAuthentications: null,
 50	      serviceDetails: null
 51	    };
 52	
 53	    serverConfig.clusters = {
 54	      'cluster-default': {
 55	        accessible: true,
 56	        apiEndpoint: '',
 57	        isKialiHome: true,
 58	        kialiInstances: [],
 59	        name: 'cluster-default',
 60	        secretName: 'test-secret'
 61	      }
 62	    };
 63	    setServerConfig(serverConfig);
 64	  });
 65	
 66	  it('renders', () => {
 67	    const wrapper = mount(
 68	      <Provider store={store}>
 69	        <MemoryRouter>
 70	          <SummaryPanelNodeComponent {...defaultProps} />
 71	        </MemoryRouter>
 72	      </Provider>
 73	    );
 74	    expect(wrapper.exists()).toBeTruthy();
 75	  });
