 79	    const wrapper = mount(
 80	      <Provider store={store}>
 81	        <MemoryRouter>
 82	          <SummaryPanelNodeComponent {...defaultProps} />
 83	        </MemoryRouter>
 84	      </Provider>
 85	    );
 86	    const weLinks = wrapper.find('a').findWhere(a => a.prop('href') && a.prop('href').includes('WorkloadEntry'));
 87	    expect(weLinks.exists()).toBeTruthy();
