 92	    nodeData = { ...nodeData, workload: 'ratings-v1', hasWorkloadEntry: [{ name: 'first_we' }, { name: 'second_we' }] };
 93	    const wrapper = mount(
 94	      <Provider store={store}>
 95	        <MemoryRouter>
