 97	        </MemoryRouter>
 98	      </Provider>
 99	    );
100	    const expandable = wrapper.find(ExpandableSection);
101	    expect(expandable.exists()).toBeTruthy();
102	    expect(
103	      expandable
104	        .children()
105	        .find('a')
106	        .findWhere(a => a.prop('href') && a.prop('href').includes('WorkloadEntry'))
107	        .exists()
108	    ).toBeTruthy();
109	  });
110	
111	  it('renders a single link to workload', () => {
112	    nodeData = { ...nodeData, workload: 'ratings-v1' };
113	    const wrapper = mount(
114	      <Provider store={store}>
115	        <MemoryRouter>
116	          <SummaryPanelNodeComponent {...defaultProps} />
117	        </MemoryRouter>
118	      </Provider>
119	    );
120	    const weLinks = wrapper.find('a').findWhere(a => a.prop('href') && a.prop('href').includes('workload'));
121	    expect(weLinks.exists()).toBeTruthy();
122	    expect(weLinks.length).toEqual(1);
123	  });
124	
125	  it('shows rank N/A when node rank undefined', () => {
126	    const props = { ...defaultProps, rankResult: { upperBound: 0 }, showRank: true };
127	    const wrapper = mount(
128	      <Provider store={store}>
129	        <MemoryRouter>
130	          <SummaryPanelNodeComponent {...props} />
131	        </MemoryRouter>
132	      </Provider>
133	    );
134	    const rankText = wrapper.find('span').findWhere(span => {
135	      const html = span.render().html();
136	      return html !== null && html.includes('Rank: N/A');
137	    });
138	    expect(rankText.exists()).toBeTruthy();
139	    expect(rankText.length).toEqual(1);
140	  });
141	
142	  it('shows node rank', () => {
143	    (nodeData as DecoratedGraphNodeData).rank = 2;
144	    const props = { ...defaultProps, rankResult: { upperBound: 3 }, showRank: true };
145	    const wrapper = mount(
146	      <Provider store={store}>
147	        <MemoryRouter>
148	          <SummaryPanelNodeComponent {...props} />
149	        </MemoryRouter>
150	      </Provider>
151	    );
152	    const rankText = wrapper.find('span').findWhere(span => {
153	      const html = span.render().html();
154	      return html !== null && html.includes('Rank: 2 / 3');
155	    });
156	    expect(rankText.exists()).toBeTruthy();
157	    expect(rankText.length).toEqual(1);
158	  });
159	
160	  it('does not render network traffic badge when netobserv is not available', () => {
161	    const wrapper = mount(
162	      <Provider store={store}>
163	        <MemoryRouter>
164	          <SummaryPanelNodeComponent {...defaultProps} />
165	        </MemoryRouter>
166	      </Provider>
167	    );
168	    // Network Traffic badge should not exist in upstream Kiali (NetObserv is OSSM Console only)
169	    const ntBadge = wrapper.find('PFBadge').findWhere(badge => {
170	      const props = badge.props();
171	      return props.badge?.name === 'NetworkTraffic';
172	    });
173	    expect(ntBadge.exists()).toBeFalsy();
174	
175	    // Network traffic link should not exist
176	    const ntLink = wrapper.find('a').findWhere(a => {
177	      const text = a.text();
178	      return text.includes('network traffic');
179	    });
180	    expect(ntLink.exists()).toBeFalsy();
181	  });
182	});

